solutions.python:
from json import dumps
class Solution:
    def __init__(self, props):
        self.memo = {}
    def memoized_component(self, props: dict) -> bool:
        stringifiedProps = dumps(props)
        if stringifiedProps in self.memo:
            return self.memo[stringifiedProps]
        self.memo[stringifiedProps] = True
        return True
